int main()
{
	int n,m,an[10],am[10],i,m1,m2,no,tog=0,j;
	m1=m2=9;
	scanf("%d%d",&n,&m);
	for(i=0;i<n;i++)
	{
	scanf("%d",&an[i]);
	if(m1>an[i])
	m1=an[i];
	}
	for(i=0;i<m;i++)
	{
	scanf("%d",&am[i]);
    if(m2>am[i])
    m2=am[i];
	}
	for(i=0;i<n;i++)
	{
		for(j=0;j<m;j++)
		{
           if(an[i]==am[j])
           {
           	if(tog==0)
           		{no=an[i];tog=1;}
           	else
           	{
           		if(no>an[i])
           			no=an[i];
           	}
           }   
        }
	}
	if(tog==1)
	{
		printf("%d",no);
	}
	else
	{
	if(m1==m2)
	printf("%d",m1);
	else
	{
	if(m1<m2)
	printf("%d",m1*10+m2);
	else
	printf("%d",m2*10+m1);
	}
}
return 0;
}

