use std::io;
use std::str::FromStr;

use std::io::prelude::*;
use std::io::BufReader;
use std::cmp::{max, min};

fn get_line() -> String {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    input
}

fn get_vec<T>() -> Vec<T>
where T: FromStr,
      <T as FromStr>::Err: std::fmt::Debug,
{
    get_line().split_whitespace().map(|k| k.parse().unwrap()).collect()
}

const N: i64 = 998_244_353;

fn extended_euclid(a: i64, b: i64) -> (i64, i64, i64) {
    if b == 0 {
        (a, 1, 0)
    } else {
        let (d0, x0, y0) = extended_euclid(b, a % b);
        (d0, y0, x0 - a / b * y0)
    }
}

fn main() {
    let (n, m) = {
        let input = get_line();
        let mut it = input.split_whitespace().map(|k| k.parse::<usize>().unwrap());
        (
            it.next().unwrap(),
            it.next().unwrap(),
            )
    };

    let f_v: Vec<usize> = get_vec();
    let s_v: Vec<usize> = get_vec();

    let first_list = f_v.into_iter()
        .fold(vec![false; 9], |mut acc, d| {
            acc[d - 1] = true;
            acc
        });

    let second_list = s_v.into_iter()
        .fold(vec![false; 9], |mut acc, d| {
            acc[d - 1] = true;
            acc
        });

    if let Some(i) = (0..first_list.len()).filter(|&i| first_list[i] && second_list[i]).min() {
        println!("{}", i + 1);
    } else {
        let f = first_list.into_iter().position(|p| p).unwrap() + 1;
        let s = second_list.into_iter().position(|p| p).unwrap() + 1;
        print!("{}", min(f, s));
        println!("{}", max(f, s));
    }
}
